INSERT INTO points_controle (phase_id, categorie_id, intitule, critere, base_legale, objet, is_custom, actif) VALUES
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Disposition administrative', 'Concerne la sécurité publique et des tiers pour toute personne exécutant des travaux', 'RPAC Art. 1-2', 'Champ d''application', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Vérifier que les mesures de protection du public sont incluses dans les devis et que l''entreprise a désigné un responsable sécurité 2.', 'Obligatoire avant de débuter, responsable sécurité désigné nommément', 'RPAC Art. 3', 'Planification & Sécurité', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Contrôler si des dispenses aux mesures du règlement ont été accordées.', 'Doit faire l''objet d''une demande et d''une décision écrites', 'RPAC Art. 4', 'Dispense', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Vérifier l''envoi de l''avis d''ouverture et de montage à la commune.', '10 jours à l''avance au moins pour l''ouverture, les grues et échafaudages', 'RPAC Art. 5', 'Annonces aux autorités', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000001', 'Contrôler la disponibilité des notes de calculs (métal, béton, bois) si exigées par l''autorité', 'Doivent respecter les normes de la Confédération et de la SIA', 'RPAC Art. 6', 'Calculs statiques', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Vérifier la résistance de la clôture et la présence de panneaux d''interdiction au public', 'Aménagements piétons obligatoires tenant compte des handicapés physiques et de la vue', 'RPAC Art. 7', 'Clôtures et Signalisation', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Contrôler la conformité des installations électriques', 'Respect strict des prescriptions de l''ASE et du fournisseur de courant', 'RPAC Art. 8', 'Installations électriques', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Vérifier l''état de la chaussée et l''entreposage des matériaux', 'Installation d''un dispositif de nettoyage (décrotteur) exigible par l''autorité', 'RPAC Art. 9', 'Propreté chaussée & Dépôts', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Vérifier l''état des passages (salage/sablage) et l''amarrage du matériel par grand vent', 'Passages rendus non glissants, machines amarrées selon les directives du constructeur', 'RPAC Art. 10', 'Intempéries & Vent', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000002', 'Contrôler la surveillance des travaux à chaud et la recherche d''amiante', 'Extincteur requis pour soudage/meulage. Contrôle post-travail si risque de feu couvant. Amiante à suspecter lors de rénovations', 'RPAC Art. 11', 'Incendie & Amiante', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003', 'S''assurer que les ouvriers connaissent leur obligation de signaler tout défaut des installations', 'Signalement immédiat au chef de toute défectuosité ou comportement dangereux', 'RPAC Art. 12-13', 'Signalement des défauts', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003', 'Contrôler le respect des normes environnementales et de protection des eaux', 'Incinération de déchets de chantiers strictement interdite', 'RPAC Art. 14', 'Environnement & Feu', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003', 'Vérifier le mode d''évacuation des déblais et gravats depuis les étages', 'Interdiction de les jeter librement ; utilisation de dévaloirs fermés exigée pour éviter la poussière', 'RPAC Art. 15', 'Évacuation des gravats', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000003', 'Vérifier l''élimination des dangers post-décoffrage', 'Les aspérités dangereuses (clous, vis) doivent être éliminées aussitôt le décoffrage effectué', 'RPAC Art. 16', 'Décoffrage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Vérifier l''habilitation du personnel effectuant le montage/démontage', 'Montage sous direction d''une personne compétente. Abattage brutal strictement interdit', 'RPAC Art. 17', 'Montage et Démontage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Contrôler l''étanchéité et l''accessibilité des passages sous échafaudage', 'Passages étanches (boue/liquides). Empêcher l''accès aux personnes étrangères au chantier', 'RPAC Art. 18', 'Protection du public', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Mesurer les dimensions des plateaux de garde (auvents) au-dessus de la rue', 'Inclinés à 45°, hauteur min 1.50 m, bord inférieur à min 4.50 m au-dessus de la chaussée. Sans vide avec la façade', 'RPAC Art. 19', 'Auvents de protection', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000004', 'Vérifier l''autorisation pour l''usage de nacelles ou ponts volants', 'Autorisation spéciale exigée, délivrée uniquement si un échafaudage de pied est impossible', 'RPAC Art. 20-21', 'Ponts volants & Nacelles', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000005', 'Évaluer la pente du toit et la hauteur de chute pour exiger l''échafaudage', 'Exigé si bas du toit ≥ 3m ET pente > 20% (métal/plastique) ou > 40% (tuile/ardoise)', 'RPAC Art. 22', 'Échafaudages de toit', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000005', 'Contrôler la pose de barres de sécurité et de crochets à demeure', 'Barres à 2 traverses, distante de min 14 cm du toit, crochets espacés de max 1.65 m 17. Crochet fermé requis pour chaque accès', 'RPAC Art. 23', 'Barres de sécurité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000005', 'Vérifier la présence de dispositifs d''ancrage pour l''entretien futur des façades', 'Obligatoire pour les façades rideaux inaccessibles aux camions-nacelles', 'RPAC Art. 24', 'Ancrages permanents', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000006', 'Contrôler les permis des grutiers et conducteurs d''engins de chantier', 'Titulaires d''un permis reconnu ou d''une attestation provisoire exigés', 'RPAC Art. 25', 'Permis de conduite', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000006', 'Vérifier l''espace libre, la mise en girouette et les autorisations de hauteur', '8 m libre au-dessus de la route. Giration libre sans charge à l''arrêt. Accord OFAC si grue > 60m ou > 25m près d''aérodrome', 'RPAC Art. 26', 'Règles Grues (Survol)', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000006', 'Vérifier l''autorisation de l''organe de contrôle', 'Autorisés uniquement en l''absence d''autres moyens techniques raisonnables', 'RPAC Art. 27', 'Hélicoptères', false, true),
  ('00000000-0000-0000-0000-000000000003', '10000000-0000-0000-0000-000000000006', 'Vérifier l''autorisation pour les travaux sur cordes au-dessus du public', 'Autorisés uniquement en l''absence d''autres moyens. Mesures spéciales exigibles', 'RPAC Art. 28', 'Travaux acrobatiques', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Pouvoir de contrôle des autorités', 'Inspection inopinée en tout temps. Plan d''organisation exigible avant montage de grue/échafaudage', 'RPAC Art. 29', 'Inspections', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Pouvoir de sanction des autorités', 'Suspension immédiate possible si la sécurité du voisinage/public est menacée', 'RPAC Art. 30', 'Suspension de chantier', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Procédure d''urgence', 'En cas de danger imminent pour les travailleurs, ordre de cesser la menace et avis immédiat à la SUVA', 'RPAC Art. 31', 'Avis SUVA (Danger grave)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000007', 'Disposition administrative', 'Recours possible au Tribunal administratif (non suspensif) 27. Commission consultative cantonale existante', 'RPAC Art. 32-33', 'Commission & Recours', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000008', 'Vérifier que chaque entrepreneur a contrôlé ses installations', 'L''entrepreneur est responsable de s''assurer de la conformité avant tout travail, même s''il n''est pas propriétaire du matériel', 'RPAC Art. 34', 'Conformité par l''entreprise', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000008', 'Contrôler la transmission de l''information en cas de sinistre', 'Avis immédiat à la commune si dommage à un tiers, et annonce à la SUVA pour tout accident de chantier', 'RPAC Art. 35', 'Annonce d''accidents', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000008', 'Disposition juridique', 'Poursuite des infractions selon la LATC et la loi sur les contraventions', 'RPAC Art. 36', 'Contraventions', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000009', 'Disposition administrative', 'Application depuis le 1er juin 2003, sous la supervision du Département des infrastructures', 'RPAC Art. 37-38', 'Entrée en vigueur', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000010', 'Disposition administrative', 'Hauteur de chute définie selon la pente (≤60° ou >60°)', 'OTConst Art. 1-2', 'Objet et définitions', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Vérifier que les mesures de sécurité et l''évaluation des dangers (ex: amiante) sont planifiées et intégrées dans les contrats d''entreprise.', 'Obligatoire avant le début des travaux', 'OTConst Art. 3', 'Planification & Contrats', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Vérifier la présence d''un Plan de Sécurité et de Protection de la Santé (PPSPS) écrit.', 'Doit inclure l''organisation des premiers secours', 'OTConst Art. 4', 'PPSPS', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Contrôler qu''une personne compétente en sécurité est désignée sur le chantier.', 'Doit pouvoir donner des directives. Renvoi de toute personne dangereuse', 'OTConst Art. 5', 'Organisation sécurité', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Contrôler le port du casque de protection (et de la jugulaire selon travaux).', 'Jugulaire requise pour travaux sur cordes, antichute et hélicoptère', 'OTConst Art. 6', 'Casque de protection', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'Vérifier le port de vêtements fluo avec bandes rétroréfléchissantes.', 'Obligatoire près des machines, engins ou voies publiques', 'OTConst Art. 7', 'Vêtements haute visibilité', false, true),
  ('00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000011', 'S''assurer que les numéros d''urgence sont affichés et le sauvetage garanti.', 'Médecin, hôpital, ambulance, police, pompiers, hélicoptère', 'OTConst Art. 8', 'Sauvetage & Urgences', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Vérifier que les postes de travail offrent la sécurité voulue avec des protections contre les chutes.', 'Pose de protections contre les chutes (Art. 22 à 29)', 'OTConst Art. 9', 'Accès sécurisés', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Contrôler que les fers d''armature et objets pointus sont protégés.', 'Fers saillants recourbés ou recouverts de protections', 'OTConst Art. 10', 'Objets tranchants', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Mesurer la largeur des voies de circulation et contrôler les accès.', 'Voies d''accès : min. 1 m. Autres : min. 60 cm. Escaliers si > 5 marches', 'OTConst Art. 11', 'Largeur des passages', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Contrôler la présence de barrières ou de panneaux interdisant l''accès aux surfaces non résistantes.', 'Passage obligatoire sur passerelles avec garde-corps des deux côtés', 'OTConst Art. 12', 'Surfaces fragiles', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'S''assurer de la solidité des passerelles.', 'Doivent être assurées contre le glissement', 'OTConst Art. 13', 'Passerelles', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Mesurer l''espace libre entre les installations en mouvement et les obstacles.', 'Espace libre exigé : 0,5 m de large et 2,5 m de haut. Sinon, barricader', 'OTConst Art. 14', 'Pièces en mouvement', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Vérifier le moyen d''accès en cas de dénivelé.', 'Escaliers ou équipements sûrs obligatoires si dénivelé > 50 cm', 'OTConst Art. 15', 'Différences de niveau', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Contrôler la solidité des ponts, bermes et digues.', 'Justificatif d''ingénieur requis. Distance bordure : min. 1 m', 'OTConst Art. 16', 'Voies de circulation', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Vérifier les protections contre la chute ou l''écroulement d''éléments.', 'Pas de danger pour les postes et passages en dessous', 'OTConst Art. 17', 'Écroulement / Chutes', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Contrôler le mode d''évacuation des gravats et matériels depuis la hauteur.', 'Zone barricadée ou utilisation de glissières/canaux fermés', 'OTConst Art. 18', 'Jet de matériel', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000012', 'Vérifier l''absence de personnes dans la zone de danger des machines.', 'Utilisation de caméras, miroirs ou d''un signaleur. Marche arrière limitée', 'OTConst Art. 19', 'Engins de chantier', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000013', 'Contrôler l''état, la surface d''appui et le type d''échelle utilisé.', 'Échelons supérieurs interdits (3 pour simples, 2 pour doubles)', 'OTConst Art. 20', 'Conformité échelles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000013', 'Vérifier que l''utilisation de l''échelle portable est justifiée.', 'Si chute > 2 m, travaux de courte durée et protection antichute exigés', 'OTConst Art. 21', 'Travaux sur échelles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Mesurer les dimensions des garde-corps périphériques (Lisse, plinthe).', 'Lisse haute à min. 100 cm, plinthe 15 cm. Écart max : 47 cm', 'OTConst Art. 22', 'Garde-corps (Conception)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Contrôler la présence de garde-corps selon la hauteur et l''environnement.', 'Obligatoire si chute > 2 m, talus > 2 m (pente > 45°), ou près de l''eau', 'OTConst Art. 23', 'Garde-corps (Usage)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Vérifier les protections à l''intérieur du bâtiment.', 'Garde-corps (1 lisse haute min.) requis si dénivelé > 50 cm', 'OTConst Art. 24', 'Dénivelé intérieur', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Contrôler la protection des ouvertures dans les sols.', 'Couverture résistante solidement fixée ou garde-corps', 'OTConst Art. 25', 'Trémies / Ouvertures', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Vérifier le montage des échafaudages lors de la construction de bâtiments.', 'Requis dès 3 m de chute. Garde-corps doit dépasser la zone de 80 cm', 'OTConst Art. 26', 'Échafaudage de façade', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Contrôler visuellement l''état des filets de sécurité.', 'Utilisation pour chute > 3 m. Contrôle visuel quotidien obligatoire', 'OTConst Art. 27', 'Filets et Retenue', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Vérifier la fixation avant l''accès.', 'Accès autorisé uniquement si les éléments sont fixés', 'OTConst Art. 28', 'Éléments préfabriqués', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000014', 'Contrôler les justificatifs si un garde-corps ou échafaudage est impossible.', 'Mesures doivent être fixées par écrit par un spécialiste de la sécurité', 'OTConst Art. 29', 'Mesures équivalentes', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000015', 'Vérifier le repérage de réseaux dangereux avant les travaux (gaz, élec).', 'Mesures fixées par écrit avec le propriétaire. Interruption si découverte', 'OTConst Art. 30', 'Installations existantes', false, true),
  ('00000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000015', 'Contrôler les coffrets électriques de chantier.', 'Prises ≤ 32 A protégées par disjoncteur différentiel 30 mA', 'OTConst Art. 31', 'Électricité', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Vérifier l''information aux travailleurs si présence d''amiante suspectée.', 'Interruption immédiate et information du maître d''ouvrage si trouvée', 'OTConst Art. 32', 'Polluants (Amiante/PCB)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Contrôler l''air ambiant dans les espaces confinés/souterrains.', 'Entre 19% et 21% d''O2. Contrôle régulier. Appareils respi si besoin', 'OTConst Art. 33', 'Qualité de l''air', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Vérifier la présence d''extincteurs et les voies d''évacuation.', 'Barricade et panneau triangulaire requis pour les zones à risque d''explosion', 'OTConst Art. 34', 'Incendie / Explosion', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Contrôler la présence d''EPI et de sauvetage près de l''eau.', 'Gilets de sauvetage, bouées, bateaux (pour eaux courantes)', 'OTConst Art. 35', 'Risque de noyade', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Contrôler le port des protections auditives.', 'Port obligatoire si la valeur limite d''exposition est dépassée', 'OTConst Art. 36', 'Bruit', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'S''assurer de la protection contre les conditions climatiques extrêmes.', 'Mesures contre le soleil, la forte chaleur et le froid', 'OTConst Art. 37', 'Climat', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Vérifier le niveau d''éclairage des accès et postes de travail.', 'Doit être "suffisant"', 'OTConst Art. 38', 'Éclairage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000016', 'Vérifier les mesures (avalanches, chutes de pierres).', 'Surveillance, alerte secours et transport garantis. Zone évacuée si danger', 'OTConst Art. 39', 'Dangers naturels', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000017', 'Contrôler la sécurité sous les monte-charges et installations de transport.', 'Zone barricadée ou surveillée. Transport humain que si prévu par le fabricant', 'OTConst Art. 40', 'Transport levage', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Contrôler la présence du pont de ferblantier ou échafaudage selon la pente.', 'Pente 10-60°: pont ferblantier. >60°: nacelle ou échafaudage', 'OTConst Art. 41', 'Mesures bords de toits', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Contrôler les dimensions de la paroi pour les toits existants (≤45°).', 'Hauteur 100 cm min, dépassement de 80 cm au-dessus du chéneau', 'OTConst Art. 42', 'Paroi de retenue toits', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Mesurer l''espace entre le pont de ferblantier et la façade.', 'Ne doit pas dépasser 30 cm', 'OTConst Art. 43', 'Distance pont/façade', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Vérifier la preuve de résistance de la toiture avant accès.', 'Si pas de preuve = non résistant. Protections exigées pour les ouvertures', 'OTConst Art. 44', 'Solidité toitures', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Contrôler les accès sur les toits fragiles (ex: fibrociment).', 'Passerelles obligatoires, ou filets/retenue si chute > 3 m', 'OTConst Art. 45', 'Toits non résistants', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000018', 'Vérifier les mesures pour travaux très courts (< 2 jours-personne).', 'Chute > 3 m = EPI antichute obligatoires', 'OTConst Art. 46', 'Travaux de peu d''ampleur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier que l''échafaudage est conçu selon la Loi sur la sécurité des produits.', 'Doit résister au vent, neige, poids et forces dynamiques', 'OTConst Art. 47', 'Capacité de charge', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler visuellement l''état des éléments tubulaires.', 'Composants courbés, pliés ou corrodés interdits', 'OTConst Art. 48', 'Pièces endommagées', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier les appuis de l''échafaudage au sol.', 'Repos sur surfaces résistantes, assuré contre le glissement', 'OTConst Art. 49', 'Fondations', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler le verrouillage des composants.', 'Assurés contre tout déplacement involontaire', 'OTConst Art. 50', 'Stabilité', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier les points de fixation à la façade.', 'Posés au fur et à mesure du montage pour résister à la traction/compression', 'OTConst Art. 51', 'Ancrages', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler les ajouts (treuils, panneaux publicitaires, bâches).', 'Validation et autorisation de l''entrepreneur en échafaudage requise', 'OTConst Art. 52', 'Éléments annexés', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier le matériau des montants porteurs de façade.', 'Perches verticales porteuses en bois strictement interdites', 'OTConst Art. 53-54', 'Conception générale', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Mesurer la largeur du platelage et vérifier la classe de charge.', 'Léger (peinture) = 60 cm (2.0 kN/m²). Lourd (maçonnerie) = 90 cm (3.0 kN/m²)', 'OTConst Art. 55', 'Charge & Largeur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier les moyens d''accès aux ponts (escaliers).', 'Distance max 25m avec chaque poste. Ascenseur requis si hauteur > 25 m', 'OTConst Art. 56', 'Accès', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Mesurer la hauteur entre les ponts et la distance au mur.', 'Hauteur : 1,9 m à 2,3 m. Distance platelage/façade : max 30 cm', 'OTConst Art. 57', 'Espacement pont/façade', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Mesurer la position du pont par rapport au bord du toit.', 'Placé 1 m max en dessous du bord du toit. Lisse à 80 cm au-dessus du toit', 'OTConst Art. 58', 'Pont de ferblantier', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier le maillage de la paroi de protection.', 'Ouvertures dans la paroi ne doivent pas dépasser 100 cm²', 'OTConst Art. 59', 'Paroi couvreur', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler la procédure de montage.', 'Doit suivre les prescriptions du fabricant', 'OTConst Art. 60', 'Montage / Démontage', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier que l''état de l''échafaudage est validé quotidiennement.', 'Gravats, neige et glace doivent être évacués des accès', 'OTConst Art. 61', 'Contrôle visuel quotidien', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier la présence des panneaux d''indication de charge.', 'Obligatoire à chaque accès, bien visible', 'OTConst Art. 62', 'Affichage charge utile', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler les zones non autorisées d''utilisation.', 'Barricadées physiquement (ex: garde-corps périphérique)', 'OTConst Art. 63', 'Blocage accès', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier qui a altéré l''échafaudage.', 'Exclusivement par/avec accord écrit de l''entrepreneur en échafaudages', 'OTConst Art. 64', 'Modifications', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Contrôler la stabilité et les roues des tours mobiles.', 'Hauteur max du fabricant. Déplacement interdit si un humain est dessus', 'OTConst Art. 65', 'Échafaudages roulants', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier le dispositif antichute en porte-à-faux.', 'Chute max 2 m. Portée horizontale d''au moins 1,5 m', 'OTConst Art. 66', 'Échaf. de retenue', false, true),
  ('00000000-0000-0000-0000-000000000004', '10000000-0000-0000-0000-000000000019', 'Vérifier la hauteur de pose des filets de protection.', 'Posés pour éviter une chute > 3 m', 'OTConst Art. 67', 'Filets de sécurité', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Mesurer la profondeur de la tranchée.', 'Étayage, blindage ou talutage obligatoire dès 1,50 m de profondeur', 'OTConst Art. 68', 'Blindage obligatoire', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Mesurer l''espace de travail dans la tranchée.', 'Min 60 cm pour conduite ≤ 40 cm. Varie avec le diamètre du tuyau', 'OTConst Art. 69', 'Largeur utile fouilles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Mesurer la largeur de travail dans les grands terrassements.', 'Min 60 cm pour toutes les phases de travail', 'OTConst Art. 70', 'Espace terrassements', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Vérifier la zone sans charge au bord de l''excavation.', 'Bord libre de 50 cm (si blindé) ou 1 m (si paroi talutée)', 'OTConst Art. 71', 'Bords libres de fouille', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Contrôler les tas de déblais près de la zone.', 'Ne doivent mettre aucun travailleur en danger (glissement)', 'OTConst Art. 72', 'Dépôts de matériaux', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Vérifier les moyens de descente dans la tranchée.', 'Escaliers avec paliers tous les 5 m max (échelles tolérées jusqu''à 5 m)', 'OTConst Art. 73', 'Accès aux fouilles', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Vérifier la circulation des véhicules autour de la fosse.', 'Bouteroues, signaux ou limitations de vitesse requis', 'OTConst Art. 74', 'Sécurité circulation bords', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Évaluer la pente du terrain.', 'Adaptée au terrain, sécurisée après forte pluie ou dégel', 'OTConst Art. 75', 'Résistance du talus', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Contrôler la présence du justificatif d''un ingénieur spécialisé.', 'Exigé si hauteur > 4 m, charges lourdes, ou présence de nappe phréatique', 'OTConst Art. 76', 'Justificatif géotechnique', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Vérifier la résistance des blindages.', 'Doit tenir compte des charges de véhicules et engins de chantier', 'OTConst Art. 77', 'Blindages (charges)', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Contrôler l''espace entre le fond/parois et le blindage.', 'Paroi max 80 cm sans étai (bas). Espaces vides derrière parois max 20 cm', 'OTConst Art. 78', 'Exécution du blindage', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Vérifier l''approbation d''un ingénieur spécialisé.', 'Justificatif requis pour injection, congélation, gunitage', 'OTConst Art. 79', 'Consolidation terrain', false, true),
  ('00000000-0000-0000-0000-000000000005', '10000000-0000-0000-0000-000000000020', 'Contrôler le bord des parois.', 'Purge immédiate des roches, souches, blocs erratiques', 'OTConst Art. 80', 'Matériaux en surplomb', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000021', 'Contrôler les mesures spéciales du PPSPS pour la déconstruction.', 'Empêcher l''écroulement inopiné, surveillance permanente par un expert', 'OTConst Art. 81', 'Démolition sécurisée', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000022', 'Vérifier l''agrément de l''entreprise si fibrociment/amiante.', 'Désamiantage obligatoire par entreprise reconnue par la SUVA', 'OTConst Art. 82', 'Entreprise reconnue', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000022', 'Contrôler les qualifications du personnel.', 'Présence continue d''un spécialiste amiante et de 2 travailleurs instruit', 'OTConst Art. 83-84', 'Spécialiste amiante', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000022', 'Vérifier le registre de formation du spécialiste.', 'Formation continue requise tous les 5 ans', 'OTConst Art. 85', 'Formation amiante', false, true),
  ('00000000-0000-0000-0000-000000000007', '10000000-0000-0000-0000-000000000022', 'Contrôler la date d''annonce des travaux de désamiantage.', 'Obligatoire auprès de la SUVA 14 jours avant exécution', 'OTConst Art. 86', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Contrôler la date d''annonce des travaux souterrains.', 'Obligatoire auprès de la SUVA 14 jours avant exécution', 'OTConst Art. 87', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier les alimentations de secours.', 'Requis pour l''aération, les pompes, l''éclairage, l''avertisseur gaz', 'OTConst Art. 88-89', 'Énergie redondante', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'S''assurer de la protection des ouvriers (chaleur/humidité).', 'Mesures appropriées selon le climat souterrain', 'OTConst Art. 90', 'Conditions climatiques', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier le concept de ventilation et de qualité de l''air.', 'Espaces ventilés obligatoires, ou mesure permanente de l''air exigée', 'OTConst Art. 91', 'Ventilation continue', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier la détection des gaz (grisou/radon).', 'Mesures si couches rocheuses contiennent du gaz naturel', 'OTConst Art. 92', 'Gaz naturel', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Contrôler le type de motorisation des engins dans le tunnel.', 'Moteurs essence/gaz liquide strictement interdits dans les souterrains', 'OTConst Art. 93', 'Moteurs à combustion', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier l''éclairage de secours.', 'Éclairage de secours central ou lampe individuelle par travailleur requis', 'OTConst Art. 94', 'Éclairage tunnel', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Contrôler les mesures lors de rénovation de tunnel sous trafic.', 'Séparation physique protégeant les travailleurs du flux', 'OTConst Art. 95', 'Trafic routier/ferré', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier la visibilité des conducteurs d''engins souterrains.', 'Visibilité permanente de la zone de danger dans le sens de marche', 'OTConst Art. 96', 'Engins de transport', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier la protection des gaines d''aération.', 'Tuyaux d''amenée d''air frais protégés contre les dommages physiques', 'OTConst Art. 97', 'Protection des installations', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Contrôler la séparation entre piétons et voies ferrées souterraines.', 'Séparation par des mesures techniques obligatoires', 'OTConst Art. 98', 'Cheminements piétons', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier les sondages préalables à l''excavation.', 'Sondage d''éboulement ou de venue d''eau avant excavation', 'OTConst Art. 99', 'Sondages / Effondrement', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier le respect de la temporisation post-tir.', 'Reprise des travaux autorisée au plus tôt 15 minutes après l''explosion. Purge obligatoire', 'OTConst Art. 100', 'Minage (Tir à l''explosif)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000023', 'Vérifier le port d''EPI haute visibilité dans le tunnel.', 'Doit couvrir "toutes les parties du corps"', 'OTConst Art. 101', 'Vêtements signalisation', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Contrôler l''obligation d''annonce pour les carrières et terrassements.', 'Obligatoire si abattage rocheux > 5000 m³ (14 jours avant)', 'OTConst Art. 102', 'Annonce SUVA', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Vérifier la pente de la découverte (front de taille).', 'Pente max 45°. Distance min de 1 m entre le pied et l''angle', 'OTConst Art. 103-104', 'Inclinaison talus', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Contrôler la hauteur des gradins.', 'Subdivisé en gradins, hauteur max 40 m. Évaluation de stabilité après tir', 'OTConst Art. 105', 'Abattage à l''explosif', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Vérifier la hauteur du front de taille.', 'Extraction depuis le bas limitée à la hauteur d''atteinte de la machine', 'OTConst Art. 106', 'Extraction', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Contrôler la sécurisation du personnel sur terrain escarpé.', 'Sape interdite. Assurage encordé obligatoire (art. 22-29)', 'OTConst Art. 107-108', 'Sape et chute de hauteur', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Vérifier la protection des cabines de machines.', 'Cabines de conduite équipées de grilles anti-chutes de pierres', 'OTConst Art. 109', 'Éboulement', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000024', 'Contrôler la purge de la paroi.', 'Après intempéries, purge obligatoire des surplombs et matériaux instables', 'OTConst Art. 110', 'Reprise après arrêt', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000025', 'Vérifier la présence d''une personne instruite.', 'Au moins 1 personne formée présente en permanence sur place', 'OTConst Art. 111-112', 'Qualifications', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000025', 'Vérifier le verrouillage mécanique/électrique des brûleurs.', 'Cadenas posé, fiche électrique débranchée, panneau de signalisation affiché', 'OTConst Art. 113', 'Consignation (LOTO)', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000025', 'Vérifier le refroidissement et l''absence de gaz (mesure).', 'Mesure préalable des gaz requise, ou appareil respiratoire indépendant', 'OTConst Art. 114', 'Gaz nocifs et Chaudières', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000025', 'Contrôler les échelles d''accès fixes.', 'Nacelle ou filet/EPI antichute si échelle fixe absente', 'OTConst Art. 115-116', 'Ascension de cheminées', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000025', 'Vérifier la présence de potelets électriques en toiture.', 'Lignes isolées, séparées de l''arrivée de courant ou protégées du contact', 'OTConst Art. 117', 'Raccordements élec.', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000026', 'Contrôler l''équipement et les binômes.', '2 travailleurs min (surveillance). 2 cordes ancrées séparément. Formation', 'OTConst Art. 118', 'Travaux encordés', false, true),
  ('00000000-0000-0000-0000-000000000006', '10000000-0000-0000-0000-000000000027', 'Mesurer l''espace utile et vérifier la surveillance.', 'Surveillant externe permanent. Si < 600 mm : travaux exclusifs par robots', 'OTConst Art. 119', 'Travail en conduites', false, true)
