ON CONFLICT (id) DO NOTHING;

-- -----------------------------------------------------------------------
-- 2. CATÉGORIES DE CONTRÔLE
-- -----------------------------------------------------------------------
ON CONFLICT (id) DO NOTHING;

-- -----------------------------------------------------------------------
-- 3. POINTS DE CONTRÔLE
-- -----------------------------------------------------------------------
ON CONFLICT DO NOTHING;

COMMIT;
